6957 ConstantRange ScalarEvolution::getRangeForAffineAR(const SCEV *Start,
6958                                                    const SCEV *Step,
6959                                                    const APInt &MaxBECount) {
6960   assert(getTypeSizeInBits(Start->getType()) ==
6961              getTypeSizeInBits(Step->getType()) &&
6962          getTypeSizeInBits(Start->getType()) == MaxBECount.getBitWidth() &&
6963          "mismatched bit widths");
6964 
6965   // First, consider step signed.
6966   ConstantRange StartSRange = getSignedRange(Start);
6967   ConstantRange StepSRange = getSignedRange(Step);
6968 
6969   // If Step can be both positive and negative, we need to find ranges for the
6970   // maximum absolute step values in both directions and union them.
6971   ConstantRange SR = getRangeForAffineARHelper(
6972       StepSRange.getSignedMin(), StartSRange, MaxBECount, /* Signed = */ true);
6973   SR = SR.unionWith(getRangeForAffineARHelper(StepSRange.getSignedMax(),
6974                                               StartSRange, MaxBECount,
6975                                               /* Signed = */ true));
6976 
6977   // Next, consider step unsigned.
6978   ConstantRange UR = getRangeForAffineARHelper(
6979       getUnsignedRangeMax(Step), getUnsignedRange(Start), MaxBECount,
6980       /* Signed = */ false);
6981 
6982   // Finally, intersect signed and unsigned ranges.
6983   return SR.intersectWith(UR, ConstantRange::Smallest);
6984 }
