4744 const SCEV *ScalarEvolution::getUMaxFromMismatchedTypes(const SCEV *LHS,
4745                                                         const SCEV *RHS) {
4746   const SCEV *PromotedLHS = LHS;
4747   const SCEV *PromotedRHS = RHS;
4748 
4749   if (getTypeSizeInBits(LHS->getType()) > getTypeSizeInBits(RHS->getType()))
4750     PromotedRHS = getZeroExtendExpr(RHS, LHS->getType());
4751   else
4752     PromotedLHS = getNoopOrZeroExtend(LHS, RHS->getType());
4753 
4754   return getUMaxExpr(PromotedLHS, PromotedRHS);
4755 }
