4757 const SCEV *ScalarEvolution::getUMinFromMismatchedTypes(const SCEV *LHS,
4758                                                         const SCEV *RHS,
4759                                                         bool Sequential) {
4760   SmallVector<const SCEV *, 2> Ops = { LHS, RHS };
4761   return getUMinFromMismatchedTypes(Ops, Sequential);
4762 }
4763 
4764 const SCEV *
4765 ScalarEvolution::getUMinFromMismatchedTypes(SmallVectorImpl<const SCEV *> &Ops,
4766                                             bool Sequential) {
4767   assert(!Ops.empty() && "At least one operand must be!");
4768   // Trivial case.
4769   if (Ops.size() == 1)
4770     return Ops[0];
4771 
4772   // Find the max type first.
4773   Type *MaxType = nullptr;
4774   for (const auto *S : Ops)
4775     if (MaxType)
4776       MaxType = getWiderType(MaxType, S->getType());
4777     else
4778       MaxType = S->getType();
4779   assert(MaxType && "Failed to find maximum type!");
4780 
4781   // Extend all ops to max type.
4782   SmallVector<const SCEV *, 2> PromotedOps;
4783   for (const auto *S : Ops)
4784     PromotedOps.push_back(getNoopOrZeroExtend(S, MaxType));
4785 
4786   // Generate umin.
4787   return getUMinExpr(PromotedOps, Sequential);
4788 }
