4790 const SCEV *ScalarEvolution::getPointerBase(const SCEV *V) {
4791   // A pointer operand may evaluate to a nonpointer expression, such as null.
4792   if (!V->getType()->isPointerTy())
4793     return V;
4794 
4795   while (true) {
4796     if (auto *AddRec = dyn_cast<SCEVAddRecExpr>(V)) {
4797       V = AddRec->getStart();
4798     } else if (auto *Add = dyn_cast<SCEVAddExpr>(V)) {
4799       const SCEV *PtrOp = nullptr;
4800       for (const SCEV *AddOp : Add->operands()) {
4801         if (AddOp->getType()->isPointerTy()) {
4802           assert(!PtrOp && "Cannot have multiple pointer ops");
4803           PtrOp = AddOp;
4804         }
4805       }
4806       assert(PtrOp && "Must have pointer op");
4807       V = PtrOp;
4808     } else // Not something we can look further into.
4809       return V;
4810   }
4811 }
