4813 /// Push users of the given Instruction onto the given Worklist.
4814 static void PushDefUseChildren(Instruction *I,
4815                                SmallVectorImpl<Instruction *> &Worklist,
4816                                SmallPtrSetImpl<Instruction *> &Visited) {
4817   // Push the def-use children onto the Worklist stack.
4818   for (User *U : I->users()) {
4819     auto *UserInsn = cast<Instruction>(U);
4820     if (isAlwaysUnknown(UserInsn))
4821       continue;
4822     if (Visited.insert(UserInsn).second)
4823       Worklist.push_back(UserInsn);
4824   }
4825 }
