4829 /// Takes SCEV S and Loop L. For each AddRec sub-expression, use its start
4830 /// expression in case its Loop is L. If it is not L then
4831 /// if IgnoreOtherLoops is true then use AddRec itself
4832 /// otherwise rewrite cannot be done.
4833 /// If SCEV contains non-invariant unknown SCEV rewrite cannot be done.
4834 class SCEVInitRewriter : public SCEVRewriteVisitor<SCEVInitRewriter> {
4835 public:
4836   static const SCEV *rewrite(const SCEV *S, const Loop *L, ScalarEvolution &SE,
4837                              bool IgnoreOtherLoops = true) {
4838     SCEVInitRewriter Rewriter(L, SE);
4839     const SCEV *Result = Rewriter.visit(S);
4840     if (Rewriter.hasSeenLoopVariantSCEVUnknown())
4841       return SE.getCouldNotCompute();
4842     return Rewriter.hasSeenOtherLoops() && !IgnoreOtherLoops
4843                ? SE.getCouldNotCompute()
4844                : Result;
4845   }
4846 
4847   const SCEV *visitUnknown(const SCEVUnknown *Expr) {
4848     if (!SE.isLoopInvariant(Expr, L))
4849       SeenLoopVariantSCEVUnknown = true;
4850     return Expr;
4851   }
4852 
4853   const SCEV *visitAddRecExpr(const SCEVAddRecExpr *Expr) {
4854     // Only re-write AddRecExprs for this loop.
4855     if (Expr->getLoop() == L)
4856       return Expr->getStart();
4857     SeenOtherLoops = true;
4858     return Expr;
4859   }
4860 
4861   bool hasSeenLoopVariantSCEVUnknown() { return SeenLoopVariantSCEVUnknown; }
4862 
4863   bool hasSeenOtherLoops() { return SeenOtherLoops; }
4864 
4865 private:
4866   explicit SCEVInitRewriter(const Loop *L, ScalarEvolution &SE)
4867       : SCEVRewriteVisitor(SE), L(L) {}
4868 
4869   const Loop *L;
4870   bool SeenLoopVariantSCEVUnknown = false;
4871   bool SeenOtherLoops = false;
4872 };
